  ornn: { diff: "EVEN", tone: "#e8b84b", tldr: "Proxy + kite \u2014 his early is weak, dodge his Q.", breakdown: "Both scale. Proxy the wave, kite his weak early through poison, and dodge his Q.", dos: ["Proxy his wave", "Kite his weak early", "Dodge his Q knockup"], donts: ["Stand near walls for his Q", "Get brittle-procced", "Stand still for his combo"], key: { slot: "Q", name: "Volcanic Rupture", cd: "10s", note: "Wall-knockup setup. Keep moving.", winT: "RUPTURE DOWN", winS: "Poison-kite + fling him." }, hold: "Hold E to fling him out of his brittle combo \u2014 kite his weak early through poison.", tip: "Both scale \u2014 proxy the wave, kite his weak early through poison, and dodge his Q.", win: "Proxy + poison-kite his early." },
  poppy: { diff: "EVEN", tone: "#e8b84b", tldr: "Proxy + kite \u2014 her W doesn\u2019t stop poison, dodge her E.", breakdown: "Proxy the wave, kite through poison (her W grounds dashes, not your kite), and dodge her E.", dos: ["Proxy his wave", "Kite through poison", "Dodge her E wall-stun"], donts: ["Get E-wall-stunned", "Get R-knocked away", "Stand still for her combo"], key: { slot: "E", name: "Heroic Charge", cd: "14s", note: "Wall-pin stun. Keep moving.", winT: "CHARGE DOWN", winS: "Poison-kite + fling her." }, hold: "Hold E to fling her when she engages \u2014 her W can\u2019t stop your kite; run her down through poison.", tip: "Proxy the wave, kite through poison (her W can\u2019t stop you), and dodge her E.", win: "Proxy + poison-kite her down." },
