  tahmkench: { diff: "EVEN", tone: "#e8b84b", tldr: "Proxy + kite \u2014 dodge his tongue, fling his dive.", breakdown: "Proxy the wave, dodge his Q tongue, and fling him out of his W dive.", dos: ["Proxy his wave", "Dodge his Q tongue", "E-fling his W dive"], donts: ["Get Q-stunned", "Fight into his W reactivate", "Stand still for his combo"], key: { slot: "Q", name: "Tongue Lash", cd: "7s", note: "His stun. Keep moving.", winT: "Q DOWN", winS: "Poison-kite + fling him." }, hold: "Hold E to fling him out of his W dive \u2014 kite through poison and dodge his Q tongue.", tip: "Proxy the wave, dodge his Q tongue, and fling him out of his W dive.", win: "Proxy + poison-kite, fling his dive." },
  zac: { diff: "EVEN", tone: "#e8b84b", tldr: "Build MR \u2014 proxy + kite, dodge his E, anti-heal.", breakdown: "Build MR, proxy the wave, dodge his E slingshot, and anti-heal his sustain.", dos: ["Build MR", "Proxy his wave", "Anti-heal his sustain"], donts: ["Let him eat blobs", "Get E-knocked-up", "Stand still for his combo"], key: { slot: "E", name: "Elastic Slingshot", cd: "16s", note: "His engage. Keep moving.", winT: "SLINGSHOT DOWN", winS: "Poison-kite + fling him." }, hold: "Hold E to fling him when he slingshots in \u2014 build MR; kite through poison and anti-heal.", tip: "Build MR, proxy the wave, dodge his E slingshot, and anti-heal his sustain.", win: "Build MR and poison-kite him." },
