  jayce: { diff: "TRICKY", tone: "#ff8b3d", tldr: "He pokes your kite \u2014 build MR, fling his melee form.", breakdown: "Jayce out-pokes your kite. Build MR, proxy the wave, and fling him when he\u2019s in melee form.", dos: ["Build MR", "Proxy his wave", "E-fling his melee form"], donts: ["Walk into his Q-gate", "Get E-knocked", "Stand still in poke range"], key: { slot: "Q", name: "Shock Blast", cd: "6s", note: "His main poke. Keep moving.", winT: "SHOCK BLAST DOWN", winS: "Poison-kite + fling him." }, hold: "Hold E to fling him when he commits to melee form \u2014 build MR; kite through poison.", tip: "Build MR, proxy the wave, and fling him when he\u2019s in melee form.", win: "Build MR and fling his melee form." },
  kayle: { diff: "FAVOURED", tone: "#3ddc97", tldr: "Crush her early \u2014 proxy her CS, run her down.", breakdown: "Kayle is helpless early. Proxy to deny her CS, run her down through poison, and snowball before her R.", dos: ["Proxy to deny her CS", "Run her down early", "Snowball before her R"], donts: ["Let her free-farm", "Fight late vs her R", "Stand still for her combo"], key: { slot: "R", name: "Divine Judgment (Invuln)", cd: "100s", note: "Her get-out at 6. Bait it.", winT: "JUDGMENT DOWN", winS: "Poison-kite + fling her." }, hold: "Hold E to fling her when she walks to CS \u2014 proxy denies her farm; run her down before she scales.", tip: "She\u2019s helpless early \u2014 proxy to deny her CS and run her down through poison before her R.", win: "Proxy her CS and run her down." },
  kennen: { diff: "EVEN", tone: "#e8b84b", tldr: "Build MR \u2014 proxy + kite, fling his combo.", breakdown: "Build MR, proxy the wave, and fling him out of his combo; kite through poison.", dos: ["Build MR", "Proxy his wave", "E-fling his combo"], donts: ["Eat free Q pokes", "Get triple-stunned", "Stand still for his combo"], key: { slot: "E", name: "Lightning Rush", cd: "10s", note: "His escape. Kite when it\u2019s down.", winT: "E DOWN", winS: "Poison-kite + fling him." }, hold: "Hold E to fling him out of his combo \u2014 build MR; kite him through poison.", tip: "Build MR, proxy the wave, and fling him out of his combo.", win: "Build MR and poison-kite him." },
  quinn: { diff: "EVEN", tone: "#e8b84b", tldr: "Proxy + kite \u2014 fling her, run her down.", breakdown: "Proxy the wave, fling her when she vaults in, and run her down through poison.", dos: ["Proxy his wave", "E-fling her vault", "Run her down"], donts: ["Fight into her blind", "Let her kite you out", "Stand still for her combo"], key: { slot: "E", name: "Vault (Dash/Blind)", cd: "11s", note: "Her self-peel. Fling out of it.", winT: "VAULT DOWN", winS: "Poison-kite + fling her." }, hold: "Hold E to fling her when she vaults in \u2014 run her down through poison.", tip: "Proxy the wave, fling her when she vaults in, and run her down through poison.", win: "Proxy + poison-kite, fling her vault." },
  rumble: { diff: "TRICKY", tone: "#ff8b3d", tldr: "His flame zones your kite \u2014 build MR, fling his over-commit.", breakdown: "Rumble\u2019s flame zones your kite. Build MR, proxy the wave, and fling him out of his flamespitter.", dos: ["Build MR", "Proxy his wave", "E-fling his over-commit"], donts: ["Stand in his flamespitter", "Sit in his R line", "Get caught in his Equalizer"], key: { slot: "W", name: "Scrap Shield", cd: "6s", note: "Bait it, then commit.", winT: "SHIELD DOWN", winS: "Poison-kite + fling him." }, hold: "Hold E to fling him out of his flamespitter \u2014 build MR; kite through poison and dodge his R.", tip: "His flame zones your kite \u2014 build MR, proxy the wave, and fling him out of his flamespitter.", win: "Build MR and fling his over-commit." },
  singed: { diff: "MIRROR", tone: "#e8b84b", tldr: "Singed mirror \u2014 whoever proxies cleaner and flings into the wave first wins.", breakdown: "Pure Singed mirror: it\u2019s a proxy and fling race. Whoever proxies cleaner and lands the fling into their own wave first wins.", dos: ["Win the proxy race", "Fling him into your wave", "Anti-heal his sustain"], donts: ["Get flung into his wave", "Chase through his poison", "Fall behind in proxy CS"], key: { slot: "E", name: "Fling", cd: "14s", note: "Whoever flings into their own wave first wins.", winT: "FLING DOWN", winS: "Poison-kite + fling him." }, hold: "Hold E to fling him into YOUR wave first \u2014 whoever proxies cleaner and lands the fling first wins.", tip: "It\u2019s a proxy + fling mirror \u2014 win the proxy race and fling him into your own minion wave first.", win: "Win the proxy race and fling first." },
  swain: { diff: "EVEN", tone: "#e8b84b", tldr: "Build MR \u2014 proxy + kite, dodge his E root.", breakdown: "Build MR, proxy the wave, dodge his E root, and anti-heal his R drain.", dos: ["Build MR + anti-heal", "Proxy his wave", "Dodge his E root"], donts: ["Fight into his R drain", "Get E-rooted", "Stand still for his combo"], key: { slot: "R", name: "Demonic Ascension", cd: "100s", note: "His drain. Kite when it\u2019s down.", winT: "ASCENSION DOWN", winS: "Poison-kite + fling him." }, hold: "Hold E to fling him when he E-roots in \u2014 build MR; anti-heal his R drain.", tip: "Build MR, proxy the wave, dodge his E root, and anti-heal his R drain.", win: "Build MR and poison-kite him." },
  teemo: { diff: "EVEN", tone: "#e8b84b", tldr: "Proxy + kite \u2014 poison ignores his blind, dodge shrooms.", breakdown: "Teemo blinds autos (not poison). Build MR, proxy, kite through poison (ignores blind), and dodge shrooms.", dos: ["Build MR + dodge shrooms", "Kite through poison (ignores blind)", "Proxy his wave"], donts: ["Auto into his blind", "Chase through shrooms", "Stand still for his combo"], key: { slot: "Q", name: "Blinding Dart", cd: "7s", note: "Blinds autos \u2014 NOT your poison aura.", winT: "BLIND DOWN", winS: "Poison-kite + fling him." }, hold: "Hold E to fling him when he over-extends \u2014 his blind can\u2019t stop your poison aura; kite him down.", tip: "His blind only stops autos \u2014 your poison aura ignores it; proxy, kite through poison, and dodge shrooms.", win: "Poison-kite through his blind." },
  vladimir: { diff: "EVEN", tone: "#e8b84b", tldr: "Build MR \u2014 proxy + kite, bully his early.", breakdown: "Vlad is weak early. Build MR, proxy the wave, and run him down through poison; bait his pool.", dos: ["Proxy his wave", "Build MR + anti-heal", "Bait his pool"], donts: ["Let him pool your combo", "Stack pure HP vs %damage", "Let him free-scale"], key: { slot: "W", name: "Sanguine Pool", cd: "22s", note: "Dodges your fling. Bait it.", winT: "POOL DOWN", winS: "Poison-kite + fling him." }, hold: "Hold E to fling him \u2014 bait his pool first, then fling when it\u2019s down; build MR.", tip: "He\u2019s weak early \u2014 proxy the wave, run him down through poison, and bait his pool.", win: "Bully him early and bait his pool." },
