  // ===== OFF-META & FLEX PICKS =====
  akshan: {"diff":"TRICKY","tone":"#ff8b3d","tldr":"Weather the poke — poison-kite him and fling the Heroic Swing commit.","breakdown":"Akshan plays around Heroic Swing. Run the wave, not the duel — W-glue his Heroic Swing, E-fling him into your tower side, and the poison does the arguing. Doran’s Shield blunts the poke war.","dos":["Proxy when Heroic Swing can’t punish","Fling him onto your side","Glue his engage"],"donts":["Fight him in a straight line","Fling into HIS wave","Chase poison-less"],"key":{"slot":"E","name":"Heroic Swing","cd":"14s","note":"His dash + camera swing escape. Engage when it's down.","winT":"SWING DOWN","winS":"Fling into goo, poison out."},"win":"Poison-kite him and fling the Heroic Swing commit."},
  cassiopeia: {"diff":"HARD","tone":"#ff5d6c","tldr":"He kites you out — survive, then poison-kite him and fling the Miasma commit.","breakdown":"Cassiopeia plays around Miasma. Run the wave, not the duel — W-glue his Miasma, E-fling him into your tower side, and the poison does the arguing. Take Mercs / MR shard — his damage is magic. Doran’s Shield blunts the poke war.","dos":["Proxy when Miasma can’t punish","Fling him onto your side","Glue his engage"],"donts":["Fight him in a straight line","Fling into HIS wave","Chase poison-less"],"key":{"slot":"W","name":"Miasma","cd":"12s","note":"Grounds you — dashes and movement abilities are disabled inside it.","winT":"MIASMA DOWN","winS":"Fling into goo, poison out."},"win":"Poison-kite him and fling the Miasma commit."},
  galio: {"diff":"EVEN","tone":"#e8b84b","tldr":"Bait his key tool — poison-kite him and fling the Justice Punch commit.","breakdown":"Galio plays around Justice Punch. Run the wave, not the duel — W-glue his Justice Punch, E-fling him into your tower side, and the poison does the arguing. Take Mercs / MR shard — his damage is magic.","dos":["Proxy when Justice Punch can’t punish","Fling him onto your side","Glue his engage"],"donts":["Fight him in a straight line","Fling into HIS wave","Chase poison-less"],"key":{"slot":"E","name":"Justice Punch","cd":"13s","note":"His dash + knockup engage. Punish him when it's down.","winT":"JUSTICE PUNCH DOWN","winS":"Fling into goo, poison out."},"win":"Poison-kite him and fling the Justice Punch commit."},
  graves: {"diff":"TRICKY","tone":"#ff8b3d","tldr":"Bait his key tool — poison-kite him and fling the Quickdraw commit.","breakdown":"Graves plays around Quickdraw. Run the wave, not the duel — W-glue his Quickdraw, E-fling him into your tower side, and the poison does the arguing.","dos":["Proxy when Quickdraw can’t punish","Fling him onto your side","Glue his engage"],"donts":["Fight him in a straight line","Fling into HIS wave","Chase poison-less"],"key":{"slot":"E","name":"Quickdraw","cd":"13s","note":"His dash + armor stacks. Engage when it's down.","winT":"QUICKDRAW DOWN","winS":"Fling into goo, poison out."},"win":"Poison-kite him and fling the Quickdraw commit."},
